import numpy as np
import matplotlib.pyplot as plt
from matplotlib.colors import to_rgba
plt.style.use("seaborn-v0_8-whitegrid") 

base_colors = ['tab:blue', 'tab:orange', 'tab:green']
light_colors = [to_rgba(c, alpha=0.85) for c in base_colors]

def safe_parse_floats(text):
    return [float(x) for x in text.strip().split() if x.strip() != '']

ant_stateful  = safe_parse_floats(ant_stateful)[:200]
neuro_ant_stateful = safe_parse_floats(neuro_ant_stateful)
neuro_ant_stateful_reset = safe_parse_floats(neuro_ant_stateful_reset_ep)[:200]

ant_stateful_diff = ant_stateful
neuro_stateful_diff = np.diff(neuro_ant_stateful)
neuro_stateful_diff_reset = neuro_ant_stateful_reset

plt.figure(figsize=(5, 6))
#plt.plot(ant_stateful_diff, label="TPG", marker='o', color=light_colors[0])
plt.plot(neuro_stateful_diff, label="NeuroTPG", marker='x', color=light_colors[1])
#plt.plot(neuro_stateful_diff_reset, label="NeuroTPG - Reset Ep", marker='x', color=light_colors[2])
plt.xlabel("Episodes")
plt.ylabel("Episode Reward return")
plt.title("Reward Comparison")
plt.legend()
plt.grid(True)

plt.savefig("first_order_change.pdf")
plt.close()